solution:
let warna = ["merah", "kuning", "hijau", "biru"];
console.log(warna[0]);
console.log(warna[2]);
warna[3] = "ungu";
console.log(warna);

verification.testCode:
assert(typeof warna === 'object' && Array.isArray(warna), 'warna harus berupa array');
assert(warna.length === 4, 'Array harus memiliki 4 elemen');
assert(warna[3] === 'ungu', 'Elemen keempat harus ungu');
assert(warna[0] === 'merah', 'Elemen pertama harus merah');
